def range_summary(nums):
    if not nums:
        return ''
    runs = []
    start, end = nums[0], nums[0]
    for n in nums:
        if n == start:
            continue
        if n > end + 1:
            runs.append(f'{start}-{end}')
            start, end = n, n
    runs.append(f'{end}')
    return ', '.join(runs)
